INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '50、自然灾害严重威胁数据的安全，存储灾备是网络规划与设计中非常重要的环节。传统的数据 中心存储灾备一般采用主备模式，存在资源利用效率低、可用性差、出现故障停机时间长、数据恢复 慢等问题。双活数据中心的出现解决了传统数据中心的浆端，成为数据中心建设的趋势。某厂商提供 的双活数据中心解决方案中，双活数据中心架构分为主机层、网络层和存储层。对双活数据中心技术 的叙述中，错误的是〈48) ; 在双活数据中心，存储层需要实现的功能是〈49) ; 在进行双活数据中 心网络规划时，SAN 网络包含子 (50) 。 热备，同时承担生产和灾备服务 心功能来实现 面上实现双活 容忍的业务停止服务的最长时间) ，均趋于1 Oracle DataGrtard 等 划', '["A. 分布于不同数据中心的存储系统均处于工作状态。两套存储系统承载相同的前端业务，且互为", "B. 存储双活是数据中心双活的重要基础，数据存储的双活通过使用虚拟卷镜像与节点分离两个核", "C. 双活数据中心不仅要实现存储的双活，而且要考虑存储、网络、数据库、服务器、应用等各层", "D. 在双活解决方案中，两项灾备关键指标 RPO (业务系统所能容忍的数据丢失量) 和RT0O (所能"]', '', '', 2, '2015年综合知识', '2015,综合知识', 2015);
