INSERT INTO questions (type, content, options, answer, explanation, difficulty, category, tags, year) VALUES ('single', '75, Symmetric, or private-key, encryption is based on a secret key that is shared by both communcating parties. The (71) party uses the secret key as part of the mathematical operation to encrypt (72) text to cipher text. The receiving party uses the same secret key to decrypt the cipher text to plain text. Asymmetric, or public-key, encryption uses two different keys for each user: one is a (73) key known only to this one user; the other is a corresponding public key, which is accessible to anyone. The private and public keys are mathematically related by the encryption algorithm. One key is used for encryption and the other for decryption, depending on the nature of the communication service being implemented. In addition, public key encryption technologies allow digital (74) to be placed on messages. A digital signature uses the sender’ s private key to encrypt some portion of the message. When the message is received, the receiver uses the sender’s (75) key to decipher the digital signature to verify the sender’ s identity. 最新多机构网课联系微信: qingsongguo888 特价促销', '["B.terminal C.sending", "D. receiving", "C. public", "D. private"]', '', '', 2, '2015年综合知识', '2015,综合知识', 2015);
